struct Position: Codable, Identifiable, Equatable {
    var id: String { symbol }
    let symbol: String
    var quantity: Double
    var avgCost: Double
    var marketPrice: Double
    var marketValue: Double { quantity * marketPrice }
    var costBasis: Double { quantity * avgCost }
    var unrealizedPnL: Double { marketValue - costBasis }
    var unrealizedPnLPercent: Double { costBasis == 0 ? 0 : unrealizedPnL / costBasis }
}

struct Portfolio: Codable, Equatable {
    var cash: Double
    var positions: [Position]
    var equity: Double { cash + positions.reduce(0) { $0 + $1.marketValue } }
    var unrealizedPnL: Double { positions.reduce(0) { $0 + $1.unrealizedPnL } }
}

