struct APIConfig: Equatable {
    var baseURL: URL
    var apiKeyId: String
    var apiSecret: String
    var accountId: String
    var enableMock: Bool
}

final class SecureSigner {
    static func hmacSHA256(key: String, message: String) -> String {
        let keyData = Data(key.utf8)
        let msgData = Data(message.utf8)
        let mac = HMAC<SHA256>.authenticationCode(for: msgData, using: SymmetricKey(data: keyData))
        return Data(mac).base64EncodedString()
    }
}

final class APIClient {
    private let session: URLSession
    private let decoder: JSONDecoder
    private let encoder: JSONEncoder
    private let configProvider: () -> APIConfig

    init(session: URLSession = .shared, configProvider: @escaping () -> APIConfig) {
        self.session = session
        self.configProvider = configProvider
        self.decoder = JSONDecoder()
        self.encoder = JSONEncoder()
        self.decoder.dateDecodingStrategy = .custom { decoder in
            let c = try decoder.singleValueContainer()
            let s = try c.decode(String.self)
            if let d = Date.iso8601Formatter().date(from: s) { return d }
            let f = ISO8601DateFormatter()
            if let d = f.date(from: s) { return d }
            throw DecodingError.dataCorruptedError(in: c, debugDescription: "Invalid date: \(s)")
        }
        self.encoder.dateEncodingStrategy = .custom { date, encoder in
            var c = encoder.singleValueContainer()
            try c.encode(Date.iso8601Formatter().string(from: date))
        }
    }

    enum APIError: Error, LocalizedError {
        case invalidURL
        case http(Int, String?)
        case decoding(String)
        case transport(String)
        case notConfigured
        case rejected(String)

        var errorDescription: String? {
            switch self {
            case .invalidURL: return "Invalid URL."
            case .http(let code, let message): return "HTTP \(code): \(message ?? "Unknown error")"
            case .decoding(let msg): return "Decoding error: \(msg)"
            case .transport(let msg): return "Network error: \(msg)"
            case .notConfigured: return "API not configured."
            case .rejected(let msg): return msg
            }
        }
    }

    private func makeRequest(path: String, method: String, body: Data?) throws -> URLRequest {
        let config = configProvider()
        guard !config.apiKeyId.isEmpty, !config.apiSecret.isEmpty, !config.accountId.isEmpty else {
            throw APIError.notConfigured
        }
        let url = config.baseURL.appendingPathComponent(path)
        var req = URLRequest(url: url)
        req.httpMethod = method
        req.httpBody = body
        req.setValue("application/json", forHTTPHeaderField: "Accept")
        if body != nil { req.setValue("application/json", forHTTPHeaderField: "Content-Type") }

        let ts = String(Int(Date().timeIntervalSince1970))
        let bodyHash = SHA256.hash(data: body ?? Data())
        let bodyDigest = Data(bodyHash).base64EncodedString()

        let canonical = [
            method.uppercased(),
            url.path,
            ts,
            config.accountId,
            bodyDigest
        ].joined(separator: "\n")

        let sig = SecureSigner.hmacSHA256(key: config.apiSecret, message: canonical)

        req.setValue(config.apiKeyId, forHTTPHeaderField: "X-API-KEY")
        req.setValue(config.accountId, forHTTPHeaderField: "X-ACCOUNT-ID")
        req.setValue(ts, forHTTPHeaderField: "X-TS")
        req.setValue(bodyDigest, forHTTPHeaderField: "X-BODY-SHA256")
        req.setValue(sig, forHTTPHeaderField: "X-SIGNATURE")
        req.timeoutInterval = 15
        return req
    }

    private func send<T: Decodable>(_ req: URLRequest, as: T.Type) async throws -> T {
        do {
            let (data, resp) = try await session.data(for: req)
            guard let http = resp as? HTTPURLResponse else { throw APIError.transport("Invalid response") }
            if !(200...299).contains(http.statusCode) {
                let msg = String(data: data, encoding: .utf8)
                throw APIError.http(http.statusCode, msg)
            }
            do {
                return try decoder.decode(T.self, from: data)
            } catch {
                let raw = String(data: data, encoding: .utf8) ?? ""
                throw APIError.decoding("\(error.localizedDescription)\n\(raw)")
            }
        } catch {
            throw APIError.transport(error.localizedDescription)
        }
    }

    func getQuote(symbol: String) async throws -> Quote {
        let req = try makeRequest(path: "v1/market/quote/\(symbol.uppercased())", method: "GET", body: nil)
        return try await send(req, as: Quote.self)
    }

    func getPortfolio() async throws -> Portfolio {
        let req = try makeRequest(path: "v1/portfolio", method: "GET", body: nil)
        return try await send(req, as: Portfolio.self)
    }

    func placeOrder(_ order: OrderRequest) async throws -> OrderResponse {
        let data = try encoder.encode(order)
        let req = try makeRequest(path: "v1/orders", method: "POST", body: data)
        return try await send(req, as: OrderResponse.self)
    }

    func cancelOrder(orderId: String) async throws -> OrderResponse {
        let req = try makeRequest(path: "v1/orders/\(orderId)/cancel", method: "POST", body: Data())
        return try await send(req, as: OrderResponse.self)
    }

    func getOrders() async throws -> [OrderResponse] {
        let req = try makeRequest(path: "v1/orders", method: "GET", body: nil)
        return try await send(req, as: [OrderResponse].self)
    }
}

// MARK: - Mock Trading Engine (Rapid Deployment Mode)

final class MockTradingEngine {
    @MainActor private(set) var portfolio: Portfolio
    @MainActor private(set) var orders: [OrderResponse] = []
    private var quoteState: [String: Quote] = [:]
    private var timerCancellable: AnyCancellable?

    init() {
        self.portfolio = Portfolio(cash: 100_000, positions: [])
    }

    func startQuotes(symbols: [String], onQuote: @escaping @MainActor (Quote) -> Void) {
        let unique = Array(Set(symbols.map { $0.uppercased() })).sorted()
        for s in unique {
            if quoteState[s] == nil {
                let base = Double.random(in: 20...450)
                quoteState[s] = Quote(symbol: s, bid: base - 0.02, ask: base + 0.02, last: base, change: 0, changePercent: 0, timestamp: Date())
            }
        }
        timerCancellable?.cancel()
        timerCancellable = Timer.publish(every: 0.8, on: .main, in: .common)
            .autoconnect()
            .sink { [weak self] _ in
                guard let self else { return }
                for sym in unique {
                    guard var q = self.quoteState[sym] else { continue }
                    let drift = Double.random(in: -0.35...0.35)
                    let last = max(0.01, q.last + drift)
                    let change = last - (q.last - q.change)
                    let changePct = (q.last - q.change) == 0 ? 0 : change / (q.last - q.change)
                    q = Quote(
                        symbol: sym,
                        bid: max(0.01, last - Double.random(in: 0.01...0.05)),
                        ask: last + Double.random(in: 0.01...0.05),
                        last: last,
                        change: change,
                        changePercent: changePct,
                        timestamp: Date()
                    )
                    self.quoteState[sym] = q
                    Task { @MainActor in
                        onQuote(q)
                    }
                }
            }
    }

    @MainActor
    func getQuote(symbol: String) -> Quote {
        let s = symbol.uppercased()
        if let q = quoteState[s] { return q }
        let base = Double.random(in: 20...450)
        let q = Quote(symbol: s, bid: base - 0.02, ask: base + 0.02, last: base, change: 0, changePercent: 0, timestamp: Date())
        quoteState[s] = q
        return q
    }

    @MainActor
    func getPortfolio() -> Portfolio {
        portfolio
    }

    @MainActor
    func getOrders() -> [OrderResponse] {
        orders.sorted { $0.updatedAt > $1.updatedAt }
    }

    @MainActor
    func placeOrder(_ order: OrderRequest) throws -> OrderResponse {
        let now = Date()
        let id = UUID().uuidString
        let symbol = order.symbol.uppercased()
        let q = getQuote(symbol: symbol)

        let execPrice: Double
        switch order.type {
        case .market:
            execPrice = (order.side == .buy) ? q.ask : q.bid
        case .limit:
            guard let limit = order.limitPrice else { throw NSError(domain: "Mock", code: 1) }
            if order.side == .buy {
                guard limit >= q.ask else {
                    return submitRejected(id: id, order: order, reason: "Limit buy too low. Current ask: \(q.ask.money())", now: now)
                }
            } else {
                guard limit <= q.bid else {
                    return submitRejected(id: id, order: order, reason: "Limit sell too high. Current bid: \(q.bid.money())", now: now)
                }
            }
            execPrice = limit
        }

        let qty = max(0, order.quantity)
        guard qty > 0 else {
            return submitRejected(id: id, order: order, reason: "Quantity must be > 0", now: now)
        }

        switch order.side {
        case .buy:
            let cost = qty * execPrice
            guard portfolio.cash >= cost else {
                return submitRejected(id: id, order: order, reason: "Insufficient cash", now: now)
            }
            portfolio.cash -= cost
            if let idx = portfolio.positions.firstIndex(where: { $0.symbol == symbol }) {
                var p = portfolio.positions[idx]
                let newQty = p.quantity + qty
                let newCostBasis = (p.avgCost * p.quantity) + cost
                p.quantity = newQty
                p.avgCost = newQty == 0 ? 0 : newCostBasis / newQty
                p.marketPrice = q.last
                portfolio.positions[idx] = p
            } else {
                portfolio.positions.append(Position(symbol: symbol, quantity: qty, avgCost: execPrice, marketPrice: q.last))
            }

        case .sell:
            guard let idx = portfolio.positions.firstIndex(where: { $0.symbol == symbol }) else {
                return submitRejected(id: id, order: order, reason: "No position to sell", now: now)
            }
            var p = portfolio.positions[idx]
            guard p.quantity >= qty else {
                return submitRejected(id: id, order: order, reason: "Insufficient shares", now: now)
            }
            let proceeds = qty * execPrice
            portfolio.cash += proceeds
            p.quantity -= qty
            p.marketPrice = q.last
            if p.quantity <= 0.0000001 {
                portfolio.positions.remove(at: idx)
            } else {
                portfolio.positions[idx] = p
            }
        }

        // update marks
        for i in portfolio.positions.indices {
            let sym = portfolio.positions[i].symbol
            let mark = quoteState[sym]?.last ?? portfolio.positions[i].marketPrice
            portfolio.positions[i].marketPrice = mark
        }

        let resp = OrderResponse(
            id: id,
            clientOrderId: order.clientOrderId,
            symbol: symbol,
            side: order.side,
            type: order.type,
            quantity: qty,
            limitPrice: order.limitPrice,
            filledQuantity: qty,
            averageFillPrice: execPrice,
            status: .filled,
            submittedAt: now,
            updatedAt: now,
            message: nil
        )
        orders.append(resp)
        return resp
    }

    @MainActor
    private func submitRejected(id: String, order: OrderRequest, reason: String, now: Date) -> OrderResponse {
        let resp = OrderResponse(
            id: id,
            clientOrderId: order.clientOrderId,
            symbol: order.symbol.uppercased(),
            side: order.side,
            type: order.type,
            quantity: order.quantity,
            limitPrice: order.limitPrice,
            filledQuantity: 0,
            averageFillPrice: nil,
            status: .rejected,
            submittedAt: now,
            updatedAt: now,
            message: reason
        )
        orders.append(resp)
        return resp
    }

    @MainActor
    func applyQuoteToPortfolio(_ quote: Quote) {
        guard let idx = portfolio.positions.firstIndex(where: { $0.symbol == quote.symbol }) else { return }
        portfolio.positions[idx].marketPrice = quote.last
    }
}

// MARK: - Trading Service

@MainActor
final class TradingService: ObservableObject {
    @Published private(set) var portfolio: Portfolio = Portfolio(cash: 0, positions: [])
    @Published private(set) var orders: [OrderResponse] = []
    @Published var quotes: [String: Quote] = [:]
    @Published var isConnected: Bool = false
    @Published var lastError: String?

    private let api: APIClient
    private var configProvider: () -> APIConfig
    private let mock: MockTradingEngine
    private var subscriptions: Set<AnyCancellable> = []

    init(configProvider: @escaping () -> APIConfig) {
        self.configProvider = configProvider
        self.api = APIClient(configProvider: configProvider)
        self.mock = MockTradingEngine()
    }

    func connect(symbols: [String]) {
        lastError = nil
        let cfg = configProvider()
        if cfg.enableMock {
            isConnected = true
            mock.startQuotes(symbols: symbols) { [weak self] q in
                guard let self else { return }
                self.quotes[q.symbol] = q
                self.mock.applyQuoteToPortfolio(q)
                self.portfolio = self.mock.getPortfolio()
            }
            self.portfolio = mock.getPortfolio()
            self.orders = mock.getOrders()
        } else {
            isConnected = true
            Task {
                await refreshAll()
            }
        }
    }

    func refreshAll() async {
        lastError = nil
        let cfg = configProvider()
        if cfg.enableMock {
            portfolio = mock.getPortfolio()
            orders = mock.getOrders()
            return
        }
        do {
            async let p = api.getPortfolio()
            async let o = api.getOrders()
            let (portfolio, orders) = try await (p, o)
            self.portfolio = portfolio
            self.orders = orders.sorted { $0.updatedAt > $1.updatedAt }
        } catch {
            lastError = error.localizedDescription
        }
    }

    func refreshQuote(symbol: String) async {
        lastError = nil
        let cfg = configProvider()
        let sym = symbol.uppercased()
        if cfg.enableMock {
            let q = mock.getQuote(symbol: sym)
            quotes[sym] = q
            mock.applyQuoteToPortfolio(q)
            portfolio = mock.getPortfolio()
            return
        }
        do {
            let q = try await api.getQuote(symbol: sym)
            quotes[sym] = q
        } catch {
            lastError = error.localizedDescription
        }
    }

    func placeOrder(symbol: String, side: OrderSide, type: OrderType, quantity: Double, limitPrice: Double?) async -> OrderResponse? {
        lastError = nil
        let cfg = configProvider()
        let req = OrderRequest(symbol: symbol.uppercased(), side: side, type: type, quantity: quantity, limitPrice: limitPrice, clientOrderId: UUID().uuidString)
        if cfg.enableMock {
            do {
                let resp = try mock.placeOrder(req)
                orders = mock.getOrders()
                portfolio = mock.getPortfolio()
                if let q = quotes[req.symbol] {
                    mock.applyQuoteToPortfolio(q)
                    portfolio = mock.getPortfolio()
                }
                if resp.status == .filled { Haptics.success() } else { Haptics.warning() }
                return resp
            } catch {
                lastError = error.localizedDescription
                Haptics.error()
                return nil
            }
        }

        do {
            let resp = try await api.placeOrder(req)
            orders = (try? await api.getOrders()) ?? orders
            portfolio = (try? await api.getPortfolio()) ?? portfolio
            if resp.status == .filled { Haptics.success() } else { Haptics.warning() }
            return resp
        } catch {
            lastError = error.localizedDescription
            Haptics.error()
            return nil
        }
    }

    func cancel(orderId: String) async {
        lastError = nil
        let cfg = configProvider()
        if cfg.enableMock {
            lastError = "Cancel not supported in mock mode."
            return
        }
        do {
            _ = try await api.cancelOrder(orderId: orderId)
            await refreshAll()
        } catch {
            lastError = error.localizedDescription
        }
    }
}

// MARK: - App Settings

@MainActor
final class AppSettings: ObservableObject {
    @Published var baseURLString: String
    @Published var apiKeyId: String
    @Published var apiSecret: String
    @Published var accountId: String
    @Published var enableMock: Bool

    private let keychain = KeychainStore.shared

    private enum Keys {
        static let baseURL = "trader.baseURL"
        static let apiKeyId = "trader.apiKeyId"
        static let apiSecret = "trader.apiSecret"
        static let accountId = "trader.accountId"
        static let enableMock = "trader.enableMock"
    }

    init() {
        let defaultBase = "https://api.examplebroker.com/"
        self.baseURLString = (try? keychain.get(Keys.baseURL)).flatMap { String(data: $0, encoding: .utf8) } ?? defaultBase
        self.apiKeyId = (try? keychain.get(Keys.apiKeyId)).flatMap { String(data: $0, encoding: .utf8) } ?? ""
        self.apiSecret = (try? keychain.get(Keys.apiSecret)).flatMap { String(data: $0, encoding: .utf8) } ?? ""
        self.accountId = (try? keychain.get(Keys.accountId)).flatMap { String(data: $0, encoding: .utf8) } ?? ""
        let mockStr = (try? keychain.get(Keys.enableMock)).flatMap { String(data: $0, encoding: .utf8) } ?? "1"
        self.enableMock = mockStr != "0"
    }

    func persist() {
        try? keychain.set(Data(baseURLString.utf8), for: Keys.baseURL)
        try? keychain.set(Data(apiKeyId.utf8), for: Keys.apiKeyId)
        try? keychain.set(Data(apiSecret.utf8), for: Keys.apiSecret)
        try? keychain.set(Data(accountId.utf8), for: Keys.accountId)
        try? keychain.set(Data((enableMock ? "1" : "0").utf8), for: Keys.enableMock)
    }

    func config() -> APIConfig {
        let url = URL(string: baseURLString.trimmingCharacters(in: .whitespacesAndNewlines)) ?? URL(string: "https://api.examplebroker.com/")!
        return APIConfig(baseURL: url, apiKeyId: apiKeyId, apiSecret: apiSecret, accountId: accountId, enableMock: enableMock)
    }
}

