struct TickerTextField: View {
    @Binding var text: String
    var body: some View {
        TextField("AAPL", text: $text)
            .textInputAutocapitalization(.characters)
            .autocorrectionDisabled()
            .font(.system(.headline, design: .rounded))
            .padding(.horizontal, 12)
            .padding(.vertical, 10)
            .background(.thinMaterial, in: RoundedRectangle(cornerRadius: 12, style: .continuous))
            .overlay(RoundedRectangle(cornerRadius: 12).strokeBorder(Color.secondary.opacity(0.25)))
            .onChange(of: text) { _, newValue in
                text = newValue.uppercased().filter { $0.isLetter || $0.isNumber || $0 == "." || $0 == "-" }
            }
    }
}

struct MoneyField: View {
    let title: String
    @Binding var value: String
    var placeholder: String
    var keyboard: UIKeyboardType = .decimalPad

    var body: some View {
        VStack(alignment: .leading, spacing: 6) {
            Text(title).font(.caption).foregroundStyle(.secondary)
            TextField(placeholder, text: $value)
                .keyboardType(keyboard)
                .textInputAutocapitalization(.never)
                .autocorrectionDisabled()
                .padding(.horizontal, 12)
                .padding(.vertical, 10)
                .background(.thinMaterial, in: RoundedRectangle(cornerRadius: 12, style: .continuous))
                .overlay(RoundedRectangle(cornerRadius: 12).strokeBorder(Color.secondary.opacity(0.25)))
                .onChange(of: value) { _, newValue in
                    let filtered = newValue.filter { "0123456789.".contains($0) }
                    var parts = filtered.split(separator: ".", omittingEmptySubsequences: false)
                    if parts.count > 2 { parts = Array(parts.prefix(2)) }
                    if parts.count == 2 {
                        let left = parts[0]
                        let right = String(parts[1]).prefix(6)
                        value = left + "." + right
                    } else {
                        value = filtered
                    }
                }
        }
    }
}

