                Spacer()
                Text(quote.last.money())
                    .font(.system(.title3, design: .rounded)).fontWeight(.semibold)
            }
            HStack {
                Text("Bid \(quote.bid.money())")
                    .font(.subheadline)
                    .foregroundStyle(.secondary)
                Spacer()
                Text("Ask \(quote.ask.money())")
                    .font(.subheadline)
                    .foregroundStyle(.secondary)
            }
            HStack {
                Text("\(quote.change.money()) (\(quote.changePercent.pct()))")
                    .font(.subheadline).fontWeight(.semibold)
                    .foregroundStyle(up ? .green : .red)
                Spacer()
                Text(quote.timestamp, style: .time)
                    .font(.caption)
                    .foregroundStyle(.secondary)
