        HStack(spacing: 12) {
            VStack(alignment: .leading, spacing: 3) {
                Text(position.symbol).font(.system(.headline, design: .rounded)).fontWeight(.semibold)
                Text("\(position.quantity.qty()) shares @ \(position.avgCost.money())")
                    .font(.caption)
                    .foregroundStyle(.secondary)
            }
            Spacer()
            VStack(alignment: .trailing, spacing: 3) {
                Text(position.marketValue.money())
                    .font(.system(.headline, design: .rounded))
                Text("\(position.unrealizedPnL.money()) (\(position.unrealizedPnLPercent.pct()))")
