struct OrderRow: View {
    let order: OrderResponse
    var body: some View {
        HStack(spacing: 12) {
            VStack(alignment: .leading, spacing: 3) {
                Text("\(order.side.rawValue.uppercased()) \(order.symbol)")
                    .font(.system(.headline, design: .rounded)).fontWeight(.semibold)
                Text("\(order.quantity.qty()) \(order.type.rawValue) • \(order.submittedAt, style: .time)")
                    .font(.caption)
                    .foregroundStyle(.secondary)
                if let msg = order.message, !msg.isEmpty, order.status == .rejected {
                    Text(msg).font(.caption).foregroundStyle(.red)
                }
            }
            Spacer()
            VStack(alignment: .trailing, spacing: 3) {
                let statusColor: Color = {
                    switch order.status {
                    case .filled: return .green
                    case .submitted, .pending: return .blue
                    case .rejected: return .red
                    case .cancelled: return .orange
                    }
                }()
                Text(order.status.rawValue.uppercased())
                    .font(.caption).fontWeight(.semibold)
                    .foregroundStyle(statusColor)
                if let avg = order.averageFillPrice {
                    Text(avg.money())
                        .font(.system(.subheadline, design: .rounded)).fontWeight(.semibold)
                } else {
                    Text("—").font(.subheadline).foregroundStyle(.secondary)
                }
            }
        }
        .padding(.vertical, 6)
    }
}

// MARK: - Trading Screen

struct TradeView: View {
    @ObservedObject var trading: TradingService

    @State private var symbol: String = "AAPL"
    @State private var side: OrderSide = .buy
    @State private var type: OrderType = .market
    @State private var qtyText: String = "1"
    @State private var limitText: String = ""
    @State private var isPlacing: Bool = false
    @State private var lastOrder: OrderResponse?

    var quote: Quote? { trading.quotes[symbol.uppercased()] }

    var body: some View {
        NavigationStack {
            ScrollView {
                VStack(spacing: 12) {
                    if let err = trading.lastError, !err.isEmpty {
                        Banner(text: err, style: .error)
                    } else if !trading.isConnected {
                        Banner(text: "Connecting…", style: .info)
                    }

                    HStack(spacing: 10) {
                        TickerTextField(text: $symbol)
                        Button {
                            Task { await trading.refreshQuote(symbol: symbol) }
                        } label: {
                            Image(systemName: "arrow.clockwise")
                                .font(.system(size: 16, weight: .semibold))
                                .frame(width: 44, height: 44)
                                .background(.thinMaterial, in: RoundedRectangle(cornerRadius: 12, style: .continuous))
                                .overlay(RoundedRectangle(cornerRadius: 12).strokeBorder(Color.secondary.opacity(0.25)))
                        }
                        .accessibilityLabel("Refresh Quote")
                    }
                    .padding(.horizontal)

                    if let q = quote {
                        QuoteCard(quote: q)
                    } else {
                        QuoteCard(quote: Quote(symbol: symbol.uppercased(), bid: 0, ask: 0, last: 0, change: 0, changePercent: 0, timestamp: Date()))
                            .redacted(reason: .placeholder)
                    }

                    VStack(spacing: 10) {
                        Picker("Side", selection: $side) {
                            ForEach(OrderSide.allCases, id: \.self) { Text($0.rawValue.uppercased()).tag($0) }
                        }
                        .pickerStyle(.segmented)

                        Picker("Type", selection: $type) {
                            ForEach(OrderType.allCases, id: \.self) { Text($0.rawValue.uppercased()).tag($0) }
                        }
                        .pickerStyle(.segmented)

                        HStack(spacing: 10) {
                            MoneyField(title: "Quantity", value: $qtyText, placeholder: "1", keyboard: .decimalPad)
                            if type == .limit {
                                MoneyField(title: "Limit Price", value: $limitText, placeholder: "0.00", keyboard: .decimalPad)
                            }
                        }

                        VStack(spacing: 10) {
                            Button {
                                place()
                            } label: {
                                HStack(spacing: 10) {
                                    if isPlacing { ProgressView().tint(.white) }
                                    Text(buttonTitle)
                                        .font(.system(.headline, design: .rounded)).fontWeight(.semibold)
                                }
                                .frame(maxWidth: .infinity)
                                .padding(.vertical, 14)
                                .foregroundStyle(.white)
                                .background(buttonColor, in: RoundedRectangle(cornerRadius: 16, style: .continuous))
                            }
                            .disabled(isPlacing || !isValid)
                            .animation(.easeInOut(duration: 0.15), value: isPlacing)
                            .accessibilityLabel("Place Order")

                            if let preview = previewLine {
                                Text(preview)
                                    .font(.caption)
                                    .foregroundStyle(.secondary)
                            }
                        }

                        if let lo = lastOrder {
                            VStack(alignment: .leading, spacing: 8) {
                                Text("Last Order").font(.headline)
                                OrderRow(order: lo)
                            }
                            .padding(14)
                            .background(.thinMaterial, in: RoundedRectangle(cornerRadius: 16, style: .continuous))
                            .overlay(RoundedRectangle(cornerRadius: 16).strokeBorder(Color.secondary.opacity(0.2)))
                        }
                    }
                    .padding(14)
                    .background(.thinMaterial, in: RoundedRectangle(cornerRadius: 16, style: .continuous))
                    .overlay(RoundedRectangle(cornerRadius: 16).strokeBorder(Color.secondary.opacity(0.2)))
                    .padding(.horizontal)

                    PortfolioHeader(portfolio: trading.portfolio)

                    VStack(alignment: .leading, spacing: 8) {
                        Text("Positions")
                            .font(.system(.headline, design: .rounded)).fontWeight(.semibold)
                        if trading.portfolio.positions.isEmpty {
                            Text("No positions yet.")
                                .font(.subheadline)
                                .foregroundStyle(.secondary)
                                .padding(.vertical, 6)
                        } else {
                            ForEach(trading.portfolio.positions.sorted(by: { $0.marketValue > $1.marketValue })) { p in
                                PositionRow(position: p)
                                Divider().opacity(0.25)
                            }
                        }
                    }
                    .padding(14)
                    .background(.thinMaterial, in: RoundedRectangle(cornerRadius: 16, style: .continuous))
                    .overlay(RoundedRectangle(cornerRadius: 16).strokeBorder(Color.secondary.opacity(0.2)))
                    .padding(.horizontal)

                    VStack(alignment: .leading, spacing: 8) {
                        Text("Recent Orders")
                            .font(.system(.headline, design: .rounded)).fontWeight(.semibold)
                        if trading.orders.isEmpty {
                            Text("No orders yet.")
                                .font(.subheadline)
                                .foregroundStyle(.secondary)
                                .padding(.vertical, 6)
                        } else {
                            ForEach(trading.orders.prefix(20), id: \.id) { o in
                                OrderRow(order: o)
                                Divider().opacity(0.25)
                            }
                        }
                    }
                    .padding(14)
                    .background(.thinMaterial, in: RoundedRectangle(cornerRadius: 16, style: .continuous))
                    .overlay(RoundedRectangle(cornerRadius: 16).strokeBorder(Color.secondary.opacity(0.2)))
                    .padding(.horizontal)

                    Spacer(minLength: 24)
                }
                .padding(.top, 10)
            }
            .navigationTitle("Trade")
            .toolbar {
                ToolbarItem(placement: .topBarTrailing) {
                    Button {
                        Task { await trading.refreshAll() }
                    } label: {
                        Image(systemName: "arrow.clockwise")
                    }
                }
            }
            .onChange(of: symbol) { _, _ in
                Task { await trading.refreshQuote(symbol: symbol) }
            }
            .onAppear {
                trading.connect(symbols: [symbol, "MSFT", "NVDA", "TSLA", "SPY"])
                Task { await trading.refreshQuote(symbol: symbol) }
            }
        }
    }

    private var isValid: Bool {
        let qty = Double(qtyText) ?? 0
        if qty <= 0 { return false }
        if type == .limit {
            let limit = Double(limitText) ?? 0
            if limit <= 0 { return false }
        }
        return !symbol.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
    }

    private var buttonTitle: String {
        let s = side == .buy ? "Buy" : "Sell"
        let t = type == .market ? "Market" : "Limit"
        return "\(s) \(t)"
    }

    private var buttonColor: Color {
        side == .buy ? Color.green : Color.red
    }

    private var previewLine: String? {
        guard let q = quote else { return nil }
        let qty = Double(qtyText) ?? 0
        if qty <= 0 { return nil }
        let px: Double
        if type == .market {
            px = (side == .buy) ? q.ask : q.bid
        } else {
            px = Double(limitText) ?? 0
            if px <= 0 { return nil }
        }
        let notional = qty * px
        let label = side == .buy ? "Estimated cost" : "Estimated proceeds"
        return "\(label): \(notional.money()) @ \(px.money())"
    }

    private func place() {
        guard isValid else { return }
        isPlacing = true
        let qty = Double(qtyText) ?? 0
        let limit = (type == .limit) ? (Double(limitText) ?? 0) : nil

        Task {
            defer { isPlacing = false }
            let resp = await trading.placeOrder(symbol: symbol, side: side, type: type, quantity: qty, limitPrice: limit)
            if let resp {
                lastOrder = resp
                if resp.status == .filled {
                    await trading.refreshQuote(symbol: symbol)
                }
            }
        }
    }
}

// MARK: - Settings Screen

struct SettingsView: View {
    @ObservedObject var settings: AppSettings
    @ObservedObject var trading: TradingService

    @State private var showSaved: Bool = false

    var body: some View {
        NavigationStack {
            Form {
                Section("Deployment") {
                    Toggle("Mock Mode (Rapid Launch)", isOn: $settings.enableMock)
                    Text(settings.enableMock ? "Using on-device mock execution & streaming quotes." : "Using live API endpoints.")
                        .font(.caption)
                        .foregroundStyle(.secondary)
                }

                Section("API") {
                    TextField("Base URL", text: $settings.baseURLString)
                        .textInputAutocapitalization(.never)
                        .autocorrectionDisabled()
                    TextField("API Key ID", text: $settings.apiKeyId)
                        .textInputAutocapitalization(.never)
                        .autocorrectionDisabled()
                    SecureField("API Secret", text: $settings.apiSecret)
                        .textInputAutocapitalization(.never)
                        .autocorrectionDisabled()
                    TextField("Account ID", text: $settings.accountId)
                        .textInputAutocapitalization(.never)
                        .autocorrectionDisabled()
                }

                Section {
                    Button("Save") {
                        settings.persist()
                        showSaved = true
                        trading.connect(symbols: ["AAPL", "MSFT", "NVDA", "TSLA", "SPY"])
                        Haptics.success()
                    }
                }

                Section("Security") {
                    Text("Secrets are stored in Keychain (This Device Only). Requests are signed with HMAC-SHA256 and include timestamp + body digest.")
                        .font(.footnote)
                        .foregroundStyle(.secondary)
                }
            }
            .navigationTitle("Settings")
            .alert("Saved", isPresented: $showSaved) {
                Button("OK", role: .cancel) { }
            } message: {
                Text("Settings updated.")
            }
        }
    }
}

// MARK: - Root App

struct RootView: View {
    @StateObject private var settings = AppSettings()
    @StateObject private var trading: TradingService

    init() {
        let settings = AppSettings()
        _settings = StateObject(wrappedValue: settings)
        _trading = StateObject(wrappedValue: TradingService(configProvider: { settings.config() }))
    }

    var body: some View {
        TabView {
            TradeView(trading: trading)
                .tabItem { Label("Trade", systemImage: "arrow.left.arrow.right") }

            SettingsView(settings: settings, trading: trading)
                .tabItem { Label("Settings", systemImage: "gearshape") }
        }
    }
}

@main
struct RapidTraderApp: App {
    var body: some Scene {
        WindowGroup {
            RootView()
        }
    }
}